20	const sum = (numbers: number[]): number =>
21	  numbers.reduce((acc, n) => acc + n, 0);
22	
23	const componentBaseForGroup = (count: number): number =>
24	  count === BLOCK_SIZE ? BLOCK_PRICE_G : count * COMPONENT_UNIT_PRICE_G;
25	
26	const componentBaseTotal = (items: Item[]): number => {
27	  const counts = new Map<string, number>();
28	  for (const item of items) {
29	    if (COMPONENT_TYPES.has(item.type)) {
30	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
31	    }
32	  }
33	  return sum([...counts.values()].map(componentBaseForGroup));
34	};
35	
36	const mainItemBase = (item: Item): number => MAIN_ITEM_BASE[item.type] ?? 0;
37	
38	const mainItemModifiers = (item: Item): number =>
39	  item.cursed ? mainItemBase(item) * 0.5 : 0;
40	
41	const firstInsuranceSurcharge = (policyBase: number): number => policyBase / 10;
42	
43	const loyaltyDiscount = (policyBase: number, yearsWithMHPCO: number): number =>
44	  yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
45	
46	const quotePremium = (items: Item[], yearsWithMHPCO: number): number => {
47	  const mainItems = items.filter((i) => !COMPONENT_TYPES.has(i.type));
48	  const policyBase = sum(mainItems.map(mainItemBase)) + componentBaseTotal(items);
49	  const itemModifiersTotal = sum(mainItems.map(mainItemModifiers));
50	  return Math.ceil(
51	    policyBase + itemModifiersTotal + firstInsuranceSurcharge(policyBase) - loyaltyDiscount(policyBase, yearsWithMHPCO) + PROCESSING_FEE_G,
52	  );
53	};
54	
55	export const runScenario = (scenario: unknown): unknown => {
56	  const s = scenario as Scenario;
57	  const items = s.steps[0].items;
58	  return { results: [{ premium: quotePremium(items, s.customer.yearsWithMHPCO) }] };
59	};
